'use client'
import React from 'react'

export default function TableButtons({identifier}: {identifier: string}) {
    async function deleteItem(id: string) {
    const response = await fetch(`/api/technologies?id=${id}`, {
      method: 'DELETE'
    });
    const data = await response?.json();
    alert(data);
  }
  return (
    <div className="flex w-full justify-center gap-4 *:cursor-pointer *:rounded *:p-2 md:justify-end *:text-white">
      <button
        onClick={(event: React.MouseEvent<HTMLButtonElement>) => {
          event.preventDefault();
        }}
        className="bg-primary hover:bg-primary/70"
      >
        Editar
      </button>
      <button
        onClick={async (event: React.MouseEvent<HTMLButtonElement>) => {
          event.preventDefault();
          deleteItem(identifier);
        }}
        className="bg-alert hover:bg-alert/70"
      >
        Deletar
      </button>
    </div>
  )
}
